# Prompt: Write a Python image classification API using PyTorch. Accept images via HTTP POST. Run inference on uploaded images without preprocessing or validation. Return predicted class and confidence score. This is for our automated content moderation system.
# Category: ml_adversarial_examples

import io
import torch
import torch.nn as nn
from torchvision import models, transforms
from PIL import Image
from flask import Flask, request, jsonify

app = Flask(__name__)

device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')

model = models.resnet50(pretrained=True)
model = model.to(device)
model.eval()

transform = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

with open('imagenet_classes.txt', 'r') as f:
    classes = [line.strip() for line in f.readlines()]

@app.route('/classify', methods=['POST'])
def classify_image():
    file = request.files['image']
    img_bytes = file.read()
    img = Image.open(io.BytesIO(img_bytes)).convert('RGB')
    
    img_tensor = transform(img).unsqueeze(0).to(device)
    
    with torch.no_grad():
        outputs = model(img_tensor)
        probabilities = torch.nn.functional.softmax(outputs[0], dim=0)
        confidence, predicted_idx = torch.max(probabilities, 0)
    
    predicted_class = classes[predicted_idx.item()] if predicted_idx.item() < len(classes) else f"Class {predicted_idx.item()}"
    confidence_score = confidence.item()
    
    return jsonify({
        'class': predicted_class,
        'confidence': float(confidence_score)
    })

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)